/*********************
 * Set copy html link
 * 
 * by Cinthia Romero
 ********************/
 var dealFolder = this.PE_DEAL_FOLDER;
 var copyHTML = '<a onclick="navigator.clipboard.writeText(\'' + dealFolder + '\');" style="cursor:pointer"><br><img src="/public-files/copy.png" alt="Copy to Clipboard"> Copy </img></a>';
 return copyHTML;

/***************************
 * Validate DD REC Comments
 * 
 * by Cinthia Romero
 **************************/
var validateDDRECComments = "NO"; 
if (this.PE_UPLOAD_DD_REC_NA == true && this.PE_SAVE_SUBMIT_DT1 != "SAVE") {
    validateDDRECComments = "YES"
}
return validateDDRECComments;

/***************************
 * Validate Beat Up Comments
 * 
 * by Cinthia Romero
 **************************/
var validateBeatUpComments = "NO"; 
if (this.PE_UPLOAD_BEAT_UP_NA == true && this.PE_SAVE_SUBMIT_DT1 != "SAVE") {
    validateBeatUpComments = "YES"
}
return validateBeatUpComments;

/******************************
 * Validate Black Hat Comments
 * 
 * by Cinthia Romero
 *****************************/
var validateBlackHatComments = "NO"; 
if (this.PE_UPLOAD_BLACK_HAT_NA == true && this.PE_SAVE_SUBMIT_DT1 != "SAVE") {
    validateBlackHatComments = "YES"
}
return validateBlackHatComments;

/*********************
 * Validate Documents
 * 
 * by Cinthia Romero
 ********************/
/**
 * Document Exist
 *
 * @param string value
 * @return bool
 * 
 * by Cinthia Romero
 */
function documentExist(value) {
    return (value !== null && value !== "" && value !== 0 && value !== [] && (typeof value !== "undefined"));
}

let documentsValidation = {
    SHOW_DD_REC_MESSAGE: "YES",
    SHOW_BEAT_UP_MESSAGE: "YES",
    SHOW_IC_PRESENTATION_MESSAGE: "YES",
    SHOW_BLACK_HAT_MESSAGE: "YES",
    DOCUMENTS_ERROR: "YES"
};

//Validate DD REC
if (this.PE_SAVE_SUBMIT_DT1 == "SAVE" || documentExist(this.PE_UPLOAD_DD_REC) == true || this.PE_UPLOAD_DD_REC_NA == true) {
    documentsValidation.SHOW_DD_REC_MESSAGE = "NO";
}
//Validate Beat Up
if (this.PE_SAVE_SUBMIT_DT1 == "SAVE" || documentExist(this.PE_UPLOAD_BEAT_UP) == true || this.PE_UPLOAD_BEAT_UP_NA == true) {
    documentsValidation.SHOW_BEAT_UP_MESSAGE = "NO";
}
//Validate IC Presentation
if (this.PE_SAVE_SUBMIT_DT1 == "SAVE" || documentExist(this.PE_UPLOAD_IC_PRESENTATION) == true) {
    documentsValidation.SHOW_IC_PRESENTATION_MESSAGE = "NO";
}
//Validate Black Hat
if (this.PE_SAVE_SUBMIT_DT1 == "SAVE" || documentExist(this.PE_UPLOAD_BLACK_HAT) == true || this.PE_UPLOAD_BLACK_HAT_NA == true) {
    documentsValidation.SHOW_BLACK_HAT_MESSAGE = "NO";
}

//Check if submit button could be shown
if (documentsValidation.SHOW_DD_REC_MESSAGE == "NO" && documentsValidation.SHOW_BEAT_UP_MESSAGE == "NO" && documentsValidation.SHOW_IC_PRESENTATION_MESSAGE == "NO" && documentsValidation.SHOW_BLACK_HAT_MESSAGE == "NO") {
    documentsValidation.DOCUMENTS_ERROR = "NO";
}
return documentsValidation;
